// src/utils/xchain-address.ts
import * as btc5 from "@scure/btc-signer";
var networkByType = {
  MAINNET: btc5.NETWORK,
  TESTNET: btc5.TEST_NETWORK,
  REGTEST: {
    ...btc5.TEST_NETWORK,
    bech32: "bcrt"
  }
};
function getSparkAddressFromTaproot(taprootAddress) {
  for (const networkType of ["MAINNET", "TESTNET", "REGTEST"]) {
    try {
      const result = btc5.Address(networkByType[networkType]).decode(taprootAddress);
      if (result.type === "tr") {
        const outputPublicKey = result.pubkey;
        return encodeSparkAddress({
          identityPublicKey: Buffer.concat([
            Buffer.from([2]),
            outputPublicKey
          ]).toString("hex"),
          network: networkType
        });
      }
    } catch (_) {
    }
  }
  throw new SparkValidationError("Invalid taproot address");
}

// src/utils/logging.ts
import { Logger } from "@lightsparkdev/core";
var LOGGER_NAMES = {
  wasm: "wasm"
};
var SparkSdkLogger = class {
  static loggers = /* @__PURE__ */ new Map();
  static get(name) {
    if (!this.loggers.has(name)) {
      this.loggers.set(name, new Logger(name));
    }
    return this.loggers.get(name);
  }
  static setLevel(name, level) {
    this.get(name).setLevel(level);
  }
  static setAllLevels(level) {
    this.loggers.forEach((logger) => logger.setLevel(level));
  }
  static setEnabled(name, enabled) {
    this.get(name).setEnabled(enabled);
  }
  static setAllEnabled(enabled) {
    this.loggers.forEach((logger) => logger.setEnabled(enabled));
  }
  static {
    Object.values(LOGGER_NAMES).forEach((name) => this.get(name));
  }
};

